/* Gets the amount of extra bits for the given dist, cfr. the DEFLATE spec. */
static int ZopfliGetDistExtraBits(int dist)
/* Valid DEFLATE distances are in [1, 32768]. */
__CPROVER_requires(dist >= 1 && dist <= 32768)
__CPROVER_assigns()
